UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

args.sql_query:
SELECT `Meter Reading (MR) Doc. No.`, HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG_FINAL AS ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09D_final
WHERE ENTSCHEIDUNG_FINAL = 'MANDATORY_READING';

SELECT `Meter Reading (MR) Doc. No.`, HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG_FINAL AS ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09D_final
WHERE ENTSCHEIDUNG_FINAL = 'DIRECT_MAIL';

SELECT `Meter Reading (MR) Doc. No.`, HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG_FINAL AS ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09D_final
WHERE ENTSCHEIDUNG_FINAL NOT IN ('MANDATORY_READING', 'DIRECT_MAIL') OR ENTSCHEIDUNG_FINAL IS NULL;
